package server

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// GetNodeSnapshot implements ddxgraphql.StateProvider.
func (s *ServerState) GetNodeSnapshot() ddxgraphql.NodeStateSnapshot {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return ddxgraphql.NodeStateSnapshot{
		ID:        s.Node.ID,
		Name:      s.Node.Name,
		StartedAt: s.Node.StartedAt,
		LastSeen:  s.Node.LastSeen,
	}
}

// GetProjectSnapshots implements ddxgraphql.StateProvider.
func (s *ServerState) GetProjectSnapshots(includeUnreachable bool) []*ddxgraphql.Project {
	entries := s.GetProjects(includeUnreachable)
	out := make([]*ddxgraphql.Project, len(entries))
	for i, e := range entries {
		out[i] = projectEntryToGQL(e)
	}
	return out
}

// GetProjectSnapshotByID implements ddxgraphql.StateProvider.
func (s *ServerState) GetProjectSnapshotByID(id string) (*ddxgraphql.Project, bool) {
	entry, ok := s.GetProjectByID(id)
	if !ok {
		return nil, false
	}
	return projectEntryToGQL(entry), true
}

type beadIndexEntry struct {
	ProjectID   string
	ProjectPath string
}

// GetBeadSnapshots implements ddxgraphql.StateProvider.
//
// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
// the resolver path opens exactly one project's store; a scoped query never
// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
// empty every registered project is scanned — that is still O(projects) by
// necessity, but each project's bead.Store receives a pushed-down filter so
// non-matching beads are never materialized as BeadSnapshot values.
func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
	if projectID != "" {
		return s.GetBeadSnapshotsForProject(projectID, status, label, search)
	}
	projects := s.GetProjects()
	pred := beadFilterPredicate(status, label, search)
	var result []ddxgraphql.BeadSnapshot
	for _, proj := range projects {
		result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
	}
	return result
}

// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
// exactly one project's bead store — iteration over other projects is not
// performed for any reason, so the cross-project loop cost is avoided for the
// common per-project bead list.
func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
	if projectID == "" {
		return nil
	}
	proj, ok := s.GetProjectByID(projectID)
	if !ok {
		return nil
	}
	pred := beadFilterPredicate(status, label, search)
	return s.beadSnapshotsForProjectEntry(proj, pred)
}

// beadStoreOpenHook is a test-only hook: when non-nil, every call to
// beadSnapshotsForProjectEntry invokes it with the project path it is about
// to open. Tests use this to assert that the scoped path opens exactly one
// project's store (ddx-9ce6842a AC §3).
var beadStoreOpenHook func(projectPath string)

// beadSnapshotsForProjectEntry reads the single project's bead store, applies
// the (possibly nil) predicate at the store layer (filter pushdown), and
// returns GraphQL snapshots for the matching beads. Callers are responsible
// for deciding which projects to pass through — this helper never touches any
// other project's state.
func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
	if beadStoreOpenHook != nil {
		beadStoreOpenHook(proj.Path)
	}
	store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
	beads, err := store.ReadAllFiltered(pred)
	if err != nil {
		return nil
	}
	out := make([]ddxgraphql.BeadSnapshot, 0, len(beads))
	for _, b := range beads {
		s.rememberBeadLocation(b.ID, proj)
		out = append(out, beadSnapshotFromStoreBead(proj.ID, b))
	}
	return out
}

// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
// that applies status/label/search filters. A nil return means "match all".
func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
	if status == "" && label == "" && search == "" {
		return nil
	}
	q := strings.ToLower(search)
	return func(b bead.Bead) bool {
		if status != "" && b.Status != status {
			return false
		}
		if label != "" && !containsString(b.Labels, label) {
			return false
		}
		if q != "" {
			if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
				return false
			}
		}
		return true
	}
}

// GetBeadSnapshot implements ddxgraphql.StateProvider.
func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
	if id == "" {
		return nil, false
	}

	if loc, ok := s.lookupBeadLocation(id); ok {
		proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
		if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
			return snap, true
		}
		s.forgetBeadLocation(id)
	}

	for _, proj := range s.GetProjects() {
		if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
			s.rememberBeadLocation(id, proj)
			return snap, true
		}
	}
	return nil, false
}

func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry) {
	if id == "" || proj.ID == "" || proj.Path == "" {
		return
	}
	s.beadIndexMu.Lock()
	defer s.beadIndexMu.Unlock()
	if s.beadIndex == nil {
		s.beadIndex = make(map[string]beadIndexEntry)
	}
	s.beadIndex[id] = beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
}

func (s *ServerState) lookupBeadLocation(id string) (beadIndexEntry, bool) {
	s.beadIndexMu.RLock()
	defer s.beadIndexMu.RUnlock()
	if s.beadIndex == nil {
		return beadIndexEntry{}, false
	}
	loc, ok := s.beadIndex[id]
	return loc, ok
}

func (s *ServerState) forgetBeadLocation(id string) {
	s.beadIndexMu.Lock()
	defer s.beadIndexMu.Unlock()
	delete(s.beadIndex, id)
}

func readBeadSnapshotFromProject(proj ProjectEntry, id string) (*ddxgraphql.BeadSnapshot, bool) {
	store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
	b, err := store.Get(id)
	if err != nil {
		return nil, false
	}
	snap := beadSnapshotFromStoreBead(proj.ID, *b)
	return &snap, true
}

func beadSnapshotFromStoreBead(projectID string, b bead.Bead) ddxgraphql.BeadSnapshot {
	snap := ddxgraphql.BeadSnapshot{
		ProjectID:   projectID,
		ID:          b.ID,
		Title:       b.Title,
		Status:      b.Status,
		Priority:    b.Priority,
		IssueType:   b.IssueType,
		Owner:       b.Owner,
		CreatedAt:   b.CreatedAt,
		CreatedBy:   b.CreatedBy,
		UpdatedAt:   b.UpdatedAt,
		Labels:      b.Labels,
		Parent:      b.Parent,
		Description: b.Description,
		Acceptance:  b.Acceptance,
		Notes:       b.Notes,
	}
	for _, d := range b.Dependencies {
		snap.Dependencies = append(snap.Dependencies, ddxgraphql.BeadDependencySnapshot{
			IssueID:     d.IssueID,
			DependsOnID: d.DependsOnID,
			Type:        d.Type,
			CreatedAt:   d.CreatedAt,
			CreatedBy:   d.CreatedBy,
			Metadata:    d.Metadata,
		})
	}
	return snap
}

func projectEntryToGQL(e ProjectEntry) *ddxgraphql.Project {
	p := &ddxgraphql.Project{
		ID:           e.ID,
		Name:         e.Name,
		Path:         e.Path,
		RegisteredAt: e.RegisteredAt.UTC().Format(time.RFC3339),
		LastSeen:     e.LastSeen.UTC().Format(time.RFC3339),
	}
	if e.GitRemote != "" {
		p.GitRemote = &e.GitRemote
	}
	if e.Unreachable {
		b := true
		p.Unreachable = &b
	}
	if e.TombstonedAt != nil {
		ts := e.TombstonedAt.UTC().Format(time.RFC3339)
		p.TombstonedAt = &ts
	}
	return p
}

// ─── Worker queries ──────────────────────────────────────────────────────────

// GetWorkersGraphQL implements ddxgraphql.StateProvider.
// Reads worker records from disk and returns them as GraphQL Worker values.
// If projectID is non-empty, only workers for that project are returned.
// An unknown projectID returns an empty list (not an error).

// GetWorkersGraphQL implements ddxgraphql.StateProvider.
// Reads worker records from disk and returns them as GraphQL Worker values.
// If projectID is non-empty, only workers for that project are returned.
// An unknown projectID returns an empty list (not an error).
//
// WorkerRecord stores the project's filesystem path in ProjectRoot, but the
// GraphQL argument is a project id (e.g. proj-96d7ea83). Resolve the id to a
// path via the project registry before filtering so the two representations
// match; previously this compared id→path directly and filtered out every
// worker on per-project queries.
func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
	if s.workingDir == "" {
		return nil
	}
	expectedPath := ""
	if projectID != "" {
		proj, ok := s.GetProjectByID(projectID)
		if !ok {
			return nil
		}
		expectedPath = proj.Path
	}
	workersDir := filepath.Join(s.workingDir, ".ddx", "workers")
	entries, err := os.ReadDir(workersDir)
	if err != nil {
		return nil
	}
	var out []*ddxgraphql.Worker
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
		if err != nil {
			continue
		}
		var rec WorkerRecord
		if err := json.Unmarshal(data, &rec); err != nil {
			continue
		}
		if expectedPath != "" && rec.ProjectRoot != expectedPath {
			continue
		}
		out = append(out, workerFromRecord(rec))
	}
	// Newest first.
	sort.Slice(out, func(i, j int) bool {
		si, sj := out[i].StartedAt, out[j].StartedAt
		if si == nil || sj == nil {
			return si != nil
		}
		ti, _ := time.Parse(time.RFC3339, *si)
		tj, _ := time.Parse(time.RFC3339, *sj)
		return ti.After(tj)
	})
	return out
}

// GetWorkerGraphQL implements ddxgraphql.StateProvider.
func (s *ServerState) GetWorkerGraphQL(id string) (*ddxgraphql.Worker, bool) {
	if s.workingDir == "" {
		return nil, false
	}
	data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
	if err != nil {
		return nil, false
	}
	var rec WorkerRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return nil, false
	}
	return workerFromRecord(rec), true
}

// GetWorkerLogGraphQL implements ddxgraphql.StateProvider.
func (s *ServerState) GetWorkerLogGraphQL(id string) *ddxgraphql.WorkerLog {
	if s.workingDir == "" {
		return &ddxgraphql.WorkerLog{}
	}
	// Read the worker record to find the log path.
	data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
	if err != nil {
		return &ddxgraphql.WorkerLog{}
	}
	var rec WorkerRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return &ddxgraphql.WorkerLog{}
	}
	stdout := ""
	if rec.StdoutPath != "" {
		logPath := rec.StdoutPath
		if !filepath.IsAbs(logPath) {
			logPath = filepath.Join(s.workingDir, logPath)
		}
		if raw, err := os.ReadFile(logPath); err == nil {
			stdout = string(raw)
		}
	}
	return &ddxgraphql.WorkerLog{Stdout: stdout, Stderr: ""}
}

// GetWorkerProgressGraphQL implements ddxgraphql.StateProvider.
func (s *ServerState) GetWorkerProgressGraphQL(id string) []*ddxgraphql.PhaseTransition {
	if s.workingDir == "" {
		return nil
	}
	data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
	if err != nil {
		return nil
	}
	var rec WorkerRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return nil
	}
	out := make([]*ddxgraphql.PhaseTransition, len(rec.RecentPhases))
	for i, p := range rec.RecentPhases {
		out[i] = &ddxgraphql.PhaseTransition{
			Phase:    p.Phase,
			Ts:       p.TS.UTC().Format(time.RFC3339),
			PhaseSeq: p.PhaseSeq,
		}
	}
	return out
}

// GetWorkerPromptGraphQL implements ddxgraphql.StateProvider.
func (s *ServerState) GetWorkerPromptGraphQL(id string) string {
	if s.workingDir == "" {
		return ""
	}
	raw, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "spec.json"))
	if err != nil {
		return ""
	}
	return string(raw)
}

// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
	attempts := rec.Attempts
	successes := rec.Successes
	failures := rec.Failures
	w := &ddxgraphql.Worker{
		ID:           rec.ID,
		Kind:         rec.Kind,
		State:        rec.State,
		ProjectRoot:  rec.ProjectRoot,
		Attempts:     &attempts,
		Successes:    &successes,
		Failures:     &failures,
		RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
	}
	if rec.Status != "" {
		w.Status = &rec.Status
	}
	if rec.Harness != "" {
		w.Harness = &rec.Harness
	}
	if rec.Provider != "" {
		w.Provider = &rec.Provider
	}
	if rec.Model != "" {
		w.Model = &rec.Model
	}
	if rec.Effort != "" {
		w.Effort = &rec.Effort
	}
	if rec.Once {
		b := true
		w.Once = &b
	}
	if rec.PollInterval != "" {
		w.PollInterval = &rec.PollInterval
	}

// LastAttemptInfo summarises the most recently completed attempt.
type LastAttemptInfo struct {
	AttemptID string    `json:"attempt_id"`
	BeadID    string    `json:"bead_id"`
	Phase     string    `json:"phase"`
	StartedAt time.Time `json:"started_at"`
	EndedAt   time.Time `json:"ended_at"`
	ElapsedMS int64     `json:"elapsed_ms"`
}

type WorkerRecord struct {
	ID             string                 `json:"id"`
	Kind           string                 `json:"kind"`
	State          string                 `json:"state"`
	Status         string                 `json:"status,omitempty"`
	ProjectRoot    string                 `json:"project_root"`
	Harness        string                 `json:"harness,omitempty"`
	Provider       string                 `json:"provider,omitempty"`
	Model          string                 `json:"model,omitempty"`
	Profile        string                 `json:"profile,omitempty"`
	Effort         string                 `json:"effort,omitempty"`
	Once           bool                   `json:"once,omitempty"`
	PollInterval   string                 `json:"poll_interval,omitempty"`
	StartedAt      time.Time              `json:"started_at,omitempty"`
	FinishedAt     time.Time              `json:"finished_at,omitempty"`
	Error          string                 `json:"error,omitempty"`
	StdoutPath     string                 `json:"stdout_path,omitempty"`
	SpecPath       string                 `json:"spec_path,omitempty"`
	Attempts       int                    `json:"attempts,omitempty"`
	Successes      int                    `json:"successes,omitempty"`
	Failures       int                    `json:"failures,omitempty"`
	CurrentBead    string                 `json:"current_bead,omitempty"`
	LastError      string                 `json:"last_error,omitempty"`
	LastResult     *WorkerExecutionResult `json:"last_result,omitempty"`
	CurrentAttempt *CurrentAttemptInfo    `json:"current_attempt,omitempty"`
	RecentPhases   []PhaseTransition      `json:"recent_phases,omitempty"`
	LastAttempt    *LastAttemptInfo       `json:"last_attempt,omitempty"`
	LandSummary    *CoordinatorMetrics    `json:"land_summary,omitempty"`
	// PID is the OS process id of an external worker subprocess, if any.
	// Zero for purely in-process (goroutine-only) workers. Surfaced so the
	// autonomous watchdog can send SIGTERM/SIGKILL to the process group when
	// cancelling the context is not enough.
	PID int `json:"pid,omitempty"`
	// ReapReason is populated when the watchdog forcibly terminates a worker;
	// set to "watchdog" today.
	ReapReason string `json:"reap_reason,omitempty"`
}

type WorkerExecutionResult struct {
	BeadID     string `json:"bead_id,omitempty"`
	AttemptID  string `json:"attempt_id,omitempty"`
	WorkerID   string `json:"worker_id,omitempty"`
	Harness    string `json:"harness,omitempty"`
	Provider   string `json:"provider,omitempty"`
	Model      string `json:"model,omitempty"`
	Status     string `json:"status,omitempty"`
	Detail     string `json:"detail,omitempty"`
	SessionID  string `json:"session_id,omitempty"`
	BaseRev    string `json:"base_rev,omitempty"`
	ResultRev  string `json:"result_rev,omitempty"`
	RetryAfter string `json:"retry_after,omitempty"`
}

type workerHandle struct {
	record  WorkerRecord
	cancel  context.CancelFunc
	logBuf  *bytes.Buffer
	logFile *os.File
	// progressCh receives ProgressEvents from the execute-bead loop.
	// The WorkerManager drains this channel to update WorkerRecord and
	// broadcast to SSE subscribers.
	progressCh chan agent.ProgressEvent
	// progressSubs holds active SSE subscriber channels for this worker.
	progressSubs []chan agent.ProgressEvent
	// progressDone is closed when drainProgress exits, signalling that
	// no further events will arrive and all new subscriptions should
	// receive an immediately-closed channel.
	progressDone chan struct{}
	// lastPhaseTS is the wall-clock time of the most recent non-heartbeat
	// ProgressEvent. The watchdog uses this to detect stalled attempts.
	lastPhaseTS time.Time
	// reaped is set true once the watchdog has escalated this worker. It is
	// checked under m.mu to make reaping idempotent.
	reaped bool
	// stopped is set true once an operator-driven Stop has started the
	// graceful termination path. Checked under m.mu so a second Stop is a
	// no-op and runWorker can preserve the "stopped" state across its final
	// record write.
	stopped bool
}

// WorkerManager manages in-process execute-loop workers as goroutines.
type WorkerManager struct {
	projectRoot string
	rootDir     string
	// BeadWorkerFactory, when non-nil, is called by runWorker to create the
	// ExecuteBeadWorker instead of building one from the real agent runner.
	// Override in tests to inject a fake executor.
	BeadWorkerFactory func(store agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker

	// LandCoordinators is the per-project registry of land coordinators.
	// Exported so tests and server integration tests can stop coordinators
	// on teardown, or inject a custom LandingGitOps via
	// LandCoordinators.gitOpsOverride.
	LandCoordinators *coordinatorRegistry

	// Watchdog parameters. Zero values fall back to defaults:
	//   WatchdogDeadline      = 6h  (total worker runtime budget)
	//   StallDeadline         = 1h  (max phase-transition gap before reap)
	//   WatchdogCheckInterval = 1m  (how often the supervisor sweeps)
	//   WatchdogKillGrace     = 30s (SIGTERM → SIGKILL grace window)
	// Tests override these to run the watchdog on millisecond scales.
	WatchdogDeadline      time.Duration
	StallDeadline         time.Duration
	WatchdogCheckInterval time.Duration
	WatchdogKillGrace     time.Duration

	mu      sync.Mutex
	workers map[string]*workerHandle

	watchdogOnce sync.Once
	watchdogStop chan struct{}
}

const (
	defaultWatchdogDeadline      = 6 * time.Hour
	defaultStallDeadline         = 1 * time.Hour
	defaultWatchdogCheckInterval = 1 * time.Minute
	defaultWatchdogKillGrace     = 30 * time.Second
)

func NewWorkerManager(projectRoot string) *WorkerManager {
	m := &WorkerManager{
		projectRoot:      projectRoot,
		rootDir:          filepath.Join(projectRoot, ".ddx", "workers"),
		workers:          map[string]*workerHandle{},
		LandCoordinators: newCoordinatorRegistry(),
		watchdogStop:     make(chan struct{}),
	}
	m.applyServerWatchdogConfig(projectRoot)
	return m
}

// applyServerWatchdogConfig reads .ddx/config.yaml at projectRoot and applies
// any server.watchdog_deadline / server.stall_deadline overrides. Invalid or
// missing values are silently ignored — defaults are filled in by the
// watchdog loop at runtime.
func (m *WorkerManager) applyServerWatchdogConfig(projectRoot string) {
	cfg, err := config.LoadWithWorkingDir(projectRoot)
	if err != nil || cfg == nil || cfg.Server == nil {
		return
	}
	if d, err := time.ParseDuration(cfg.Server.WatchdogDeadline); err == nil && d > 0 {
		m.WatchdogDeadline = d
	}
	if d, err := time.ParseDuration(cfg.Server.StallDeadline); err == nil && d > 0 {
		m.StallDeadline = d
	}
}

// watchdogDeadlines returns the effective deadlines, applying defaults for
// any zero-valued fields.
func (m *WorkerManager) watchdogDeadlines() (watchdog, stall, check, grace time.Duration) {
	watchdog = m.WatchdogDeadline
	if watchdog <= 0 {
		watchdog = defaultWatchdogDeadline
	}
	stall = m.StallDeadline
	if stall <= 0 {
		stall = defaultStallDeadline
	}
	check = m.WatchdogCheckInterval
	if check <= 0 {
		check = defaultWatchdogCheckInterval
	}
	grace = m.WatchdogKillGrace
	if grace <= 0 {
		grace = defaultWatchdogKillGrace
	}
	return
}

func (m *WorkerManager) StartExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	// Resolve the effective project root: spec override takes priority over the
	// manager's default so callers can target any registered project.
	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}

	// Pre-flight: validate harness availability and model compatibility
	// before creating the worker record or claiming any beads.
	if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider, spec.ModelRef); err != nil {
		return WorkerRecord{}, fmt.Errorf("execute-loop: %w", err)
	}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	// Write spec
	specData, _ := json.MarshalIndent(spec, "", "  ")
	_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)

	// Open log file
	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return WorkerRecord{}, err
	}

	// Open structured event sink — loop milestones (bead.claimed, bead.result,
	// loop.start/end) land here as JSONL so log aggregators and future server
	// endpoints can parse them independently of the human-readable worker.log.
	eventsPath := filepath.Join(dir, "worker-events.jsonl")
	eventsFile, eventsErr := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if eventsErr != nil {
		eventsFile = nil // non-fatal; structured events silently disabled
	}

	record := WorkerRecord{
		ID:           id,
		Kind:         "execute-loop",
		State:        "running",
		Status:       "running",
		ProjectRoot:  effectiveRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		Profile:      agent.NormalizeRoutingProfile(spec.Profile),
		Effort:       spec.Effort,
		Once:         spec.Once,
		PollInterval: spec.PollInterval.String(),
		StdoutPath:   relToProject(m.projectRoot, logPath),
		SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
		StartedAt:    time.Now().UTC(),
	}
	_ = m.writeRecord(dir, record)

	ctx, cancel := context.WithCancel(context.Background())
	logBuf := &bytes.Buffer{}
	multiLog := io.MultiWriter(logBuf, logFile)

	progressCh := make(chan agent.ProgressEvent, 64)
	handle := &workerHandle{
		record:       record,
		cancel:       cancel,
		logBuf:       logBuf,
		logFile:      logFile,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  time.Now().UTC(),
	}

	m.mu.Lock()
	m.workers[id] = handle

	}
	_ = json.Unmarshal(body, &resp)
	msgs := make([]string, len(resp.Errors))
	for i, e := range resp.Errors {
		msgs[i] = e.Message
	}
	return msgs
}

